import{_ as r,c as a,o as l,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"개인정보처리방침: 데이터 보호 이해하기 | OpenCodeDocs","description":"OpenCodeDocs의 개인정보처리방침 및 데이터 보호 조치에 대해 알아보세요. 우리가 어떻게 귀하의 개인정보를 수집, 사용, 저장하는지, 그리고 귀하가 가지는 데이터 권리에 대해 설명합니다.","frontmatter":{"title":"개인정보처리방침: 데이터 보호 이해하기 | OpenCodeDocs","sidebarTitle":"데이터는 어디로 가나요","subtitle":"개인정보처리방침: 데이터 보호 이해하기","description":"OpenCodeDocs의 개인정보처리방침 및 데이터 보호 조치에 대해 알아보세요. 우리가 어떻게 귀하의 개인정보를 수집, 사용, 저장하는지, 그리고 귀하가 가지는 데이터 권리에 대해 설명합니다."},"headers":[],"relativePath":"ko/privacy.md","filePath":"ko/privacy.md"}'),t={name:"ko/privacy.md"};function e(n,o,s,g,h,c){return l(),a("div",null,[...o[0]||(o[0]=[i('<h1 id="개인정보처리방침" tabindex="-1">개인정보처리방침 <a class="header-anchor" href="#개인정보처리방침" aria-label="Permalink to &quot;개인정보처리방침&quot;">​</a></h1><p>최종 업데이트 날짜: 2026-01-01</p><p>OpenCodeDocs를 이용해 주셔서 감사합니다. 저희는 귀하의 개인정보와 프라이버시 보호를 매우 중요하게 생각합니다. 본 개인정보처리방침은 저희가 어떻게 귀하의 개인정보를 수집, 사용, 저장하고 보호하는지 이해하실 수 있도록 도와드립니다.</p><h2 id="_1-수집하는-정보" tabindex="-1">1. 수집하는 정보 <a class="header-anchor" href="#_1-수집하는-정보" aria-label="Permalink to &quot;1. 수집하는 정보&quot;">​</a></h2><p>OpenCodeDocs 서비스를 이용하실 때 다음 유형의 정보를 수집할 수 있습니다:</p><h3 id="계정-정보" tabindex="-1">계정 정보 <a class="header-anchor" href="#계정-정보" aria-label="Permalink to &quot;계정 정보&quot;">​</a></h3><ul><li><strong>이메일 주소</strong>: 계정 등록, 로그인 확인 및 중요 알림 전송에 사용</li><li><strong>사용자 이름</strong>: 귀하가 선택한 표시 이름</li><li><strong>GitHub 계정 정보</strong>: GitHub 로그인을 선택한 경우 공개 정보를 수집</li></ul><h3 id="사용-데이터" tabindex="-1">사용 데이터 <a class="header-anchor" href="#사용-데이터" aria-label="Permalink to &quot;사용 데이터&quot;">​</a></h3><ul><li><strong>방문 기록</strong>: 귀하가 방문한 튜토리얼 페이지와 방문 시간</li><li><strong>상호작용 행동</strong>: 코드 복사, 섹션 이동 등 작업</li><li><strong>검색 기록</strong>: 사이트 내 검색 키워드</li></ul><h3 id="기기-정보" tabindex="-1">기기 정보 <a class="header-anchor" href="#기기-정보" aria-label="Permalink to &quot;기기 정보&quot;">​</a></h3><ul><li><strong>브라우저 유형</strong>: Chrome, Firefox, Safari 등</li><li><strong>운영체제</strong>: Windows, macOS, Linux 등</li><li><strong>IP 주소</strong>: 보안 보호 및 지역 최적화에 사용</li></ul><h2 id="_2-정보-사용-방법" tabindex="-1">2. 정보 사용 방법 <a class="header-anchor" href="#_2-정보-사용-방법" aria-label="Permalink to &quot;2. 정보 사용 방법&quot;">​</a></h2><p>수집한 정보는 다음 목적에 사용됩니다:</p><ul><li><strong>서비스 제공</strong>: 튜토리얼 콘텐츠에 정상적으로 접근하고 사용할 수 있도록 보장</li><li><strong>개인화 경험</strong>: 독서 진도 및 설정 기본값 기억</li><li><strong>제품 개선</strong>: 사용 패턴을 분석하여 콘텐츠 및 기능 최적화</li><li><strong>보안 보호</strong>: 비정상적인 행동을 감지하여 남용 방지</li><li><strong>알림 전송</strong>: 튜토리얼 업데이트 알림 및 중요 공지 발송(구독 취소 가능)</li></ul><h2 id="_3-정보-공유-및-공개" tabindex="-1">3. 정보 공유 및 공개 <a class="header-anchor" href="#_3-정보-공유-및-공개" aria-label="Permalink to &quot;3. 정보 공유 및 공개&quot;">​</a></h2><p>개인정보는 판매하지 않습니다. 다음 경우에만 공유할 수 있습니다:</p><ul><li><strong>제3자 서비스 제공자</strong>: Vercel(호스팅), Plausible(분석) 등 업무 수행에 필요한 정보만 접근 가능</li><li><strong>법률 요구</strong>: 법률 또는 규정에 따라 공개 필요</li><li><strong>권익 보호</strong>: OpenCodeDocs 및 사용자 권익을 보호하기 위해 필요한 경우</li></ul><h2 id="_4-데이터-저장-및-보안" tabindex="-1">4. 데이터 저장 및 보안 <a class="header-anchor" href="#_4-데이터-저장-및-보안" aria-label="Permalink to &quot;4. 데이터 저장 및 보안&quot;">​</a></h2><ul><li><strong>저장 위치</strong>: 미국 및 아시아태평양 지역의 보안 서버에 데이터 저장</li><li><strong>암호화 조치</strong>: 전송 데이터는 TLS/SSL 암호화 사용, 민감 데이터는 AES-256 암호화 저장</li><li><strong>접근 제어</strong>: 내부 직원의 데이터 접근 권한을 엄격히 제한</li><li><strong>보유 기간</strong>: 계정 탈퇴 후 개인 데이터는 30일 이내 삭제</li></ul><h2 id="_5-귀하의-권리" tabindex="-1">5. 귀하의 권리 <a class="header-anchor" href="#_5-귀하의-권리" aria-label="Permalink to &quot;5. 귀하의 권리&quot;">​</a></h2><p>『개인정보보호법』및 GDPR에 따라 다음 권리를 가집니다:</p><ul><li><strong>접근권</strong>: 보유하고 있는 귀하의 개인정보를 볼 권리</li><li><strong>정정권</strong>: 부정확한 개인정보의 정정을 요청할 권리</li><li><strong>삭제권</strong>: 개인정보의 삭제를 요청할 권리</li><li><strong>내보내기 권리</strong>: 데이터를 공통 형식으로 내보낼 권리</li><li><strong>동의 철회</strong>: 언제든지 이전에 동의한 내용을 철회할 권리</li></ul><p>위 권리를 행사하려면 아래 연락처를 통해 저희에게 연락해 주세요.</p><h2 id="_6-cookie-정책" tabindex="-1">6. Cookie 정책 <a class="header-anchor" href="#_6-cookie-정책" aria-label="Permalink to &quot;6. Cookie 정책&quot;">​</a></h2><p>다음 유형의 Cookie를 사용합니다:</p><ul><li><strong>필수 Cookie</strong>: 로그인 상태 유지, 언어 기본값 기억</li><li><strong>분석 Cookie</strong>: 방문량 및 사용 패턴 통계(개인정보 친화적인 Plausible 사용)</li><li><strong>광고 Cookie</strong>: <ul><li>Google을 포함한 제3자 공급업체는 귀하의 사이트 및 기타 사이트에서의 방문 기록을 기반으로 광고를 게재하기 위해 Cookie를 사용합니다.</li><li>Google은 광고 Cookie를 사용하여 Google 및 파트너가 귀하의 사이트 및/또는 인터넷의 다른 사이트에서의 방문 기록을 기반으로 사용자에게 광고를 게시할 수 있도록 합니다.</li><li>사용자는 <a href="https://www.google.com/settings/ads" target="_blank" rel="noreferrer">Google 광고 설정</a>에서 개인화된 광고를 끌 수 있습니다. 또는 <a href="http://www.aboutads.info/choices/" target="_blank" rel="noreferrer">www.aboutads.info</a>에 방문하여 개인화된 광고에 사용되는 제3자 공급업체의 Cookie를 끄도록 안내할 수 있습니다.</li></ul></li></ul><p>브라우저 설정에서 Cookie를 관리할 수 있습니다. 필수 Cookie를 비활성화하면 일부 기능이 정상적으로 작동하지 않을 수 있습니다.</p><h2 id="_7-문의하기" tabindex="-1">7. 문의하기 <a class="header-anchor" href="#_7-문의하기" aria-label="Permalink to &quot;7. 문의하기&quot;">​</a></h2><p>본 개인정보처리방침에 대해 질문이 있거나 데이터 권리를 행사해야 하는 경우 다음으로 연락해 주세요:</p><ul><li><strong>이메일</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>응답 시간</strong>: 요청 후 15 영업일 이내에 답변 드리겠습니다</li></ul>',30)])])}const p=r(t,[["render",e]]);export{u as __pageData,p as default};
